def fuzzy_membership(x, membership_function):
 # Calculate degree of membership
 if membership_function == 'cold':
 return 1 if x < 15 else (20 - x) / 5 if 15 <= x <= 20 else 0
 elif membership_function == 'warm':
 return (x - 15) / 5 if 15 <= x <= 20 else 1 if 20 <= x <= 25 else (30 - x) / 5 if 25 <= x <= 30 else 0
 elif membership_function == 'hot':
 return (x - 25) / 5 if 25 <= x <= 30 else 1 if x > 30 else 0

# Example usage
x = 22
print(fuzzy_membership(x, 'cold')) # Output: 0
print(fuzzy_membership(x, 'warm')) # Output: 0.8
print(fuzzy_membership(x, 'hot')) # Output: 0

class Bird:
 def __init__(self, name):
 self.name = name
 self.fly = True

 class Penguin(Bird):
 def __init__(self, name):
 super().__init__(name)
 self.fly = False

# Example usage
tweety = Bird('Tweety')
print(tweety.fly) # Output: True
penguin_tweety = Penguin('Tweety')
print(penguin_tweety.fly) # Output: False
